-- Weather profile seed — generated by scripts/dump_weather_profile.py
-- Source: Neon cloud DB, table weather_profile (KNMI station 06280, 30-min slots)

CREATE TABLE IF NOT EXISTS weather_profile (
    timestamp           TIMESTAMPTZ PRIMARY KEY,
    wind_speed_ms       DOUBLE PRECISION,
    wind_dir_deg        DOUBLE PRECISION,
    wind_gust_ms        DOUBLE PRECISION,
    temperature_c       DOUBLE PRECISION,
    air_pressure_hpa    DOUBLE PRECISION,
    humidity_pct        DOUBLE PRECISION,
    radiation_wm2       DOUBLE PRECISION,
    sunshine_min        DOUBLE PRECISION
);

CREATE INDEX IF NOT EXISTS ix_weather_profile_timestamp ON weather_profile (timestamp);

-- Truncate before re-seeding (idempotent)
TRUNCATE weather_profile;

